import math

def log_gaussian_pdf(x, mu, var):
    return -0.5 * math.log(2 * math.pi * var) - (x - mu) ** 2 / (2 * var)

# One feature, two classes (toy from explanation)
priors = {0: 0.6, 1: 0.4}
params = {0: (4.0, 1.0), 1: (7.0, 2.0)}  # (mu, var) per class
x_new = 5.0

scores = {}
for k, (mu, var) in params.items():
    scores[k] = math.log(priors[k]) + log_gaussian_pdf(x_new, mu, var)

print("log-posterior scores:", scores)
print("predicted class:", max(scores, key=scores.get))
